# Common backbone idea: Calculate a priority index for each unvisited customer considering travel time, waiting time, and time window constraints, using abstract forces or influences derived from both spatial and temporal factors for decision making.
# {Design an algorithm that optimizes route decisions by modeling dynamic 'flow fields' where customers exert a fluid-like resistance based on distance, time pressure, and existing truck paths.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    def calculate_travel_time(pos1, pos2, speed):
        return np.linalg.norm(np.array(pos1) - np.array(pos2)) / speed

    def flow_resistance_effect(customer_pos, all_positions):
        distances = [np.linalg.norm(np.array(customer_pos) - np.array(pos)) for pos in all_positions]
        return np.sum(1 / (np.array(distances) + 1))

    def calculate_score(travel_time, customer_index, flow_resistance):
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[customer_index]

        if arrival_time > end_window:
            return float('inf')

        wait_penalty = max(0, start_window - arrival_time)

        temporal_urgency = 1.0 / (end_window - current_time + 1) if end_window > current_time else float('inf')

        return travel_time + 1.2 * wait_penalty - 0.4 * temporal_urgency + 0.5 * flow_resistance

    best_node = None
    best_score = float('inf')

    for index, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        flow_resistance = flow_resistance_effect(customer_pos, all_truck_pos + [depot_pos])
        score = calculate_score(travel_time, index, flow_resistance)

        if score < best_score:
            best_score = score
            best_node = index

    return best_node

